('chunk_9926ec898854178975','file_3393b5fbe4e9b31e26','mathematics.md','Cross-Subject Connections','- **Physics (MYP Sciences):** Rates, unit conversions and the D=S×T triangle underpin speed, velocity and acceleration; Pythagoras resolves vector components; standard form (indices) expresses very large/small quantities; graphs and gradients link to motion graphs.
- **Chemistry (MYP Sciences):** Ratio and proportion drive mole ratios and concentration; percentage calculations give percentage yield, composition and purity; significant figures and rounding relate to measurement accuracy.
- **Geography / Individuals & Societies:** Time zones and coordinates support map-reading and global scheduling; percentage change models population growth, GDP and resource change; central tendency and dispersion summarise climate and demographic data; scale ratios convert map to real distance.
- **Digital Design / Computing:** The coordinate plane maps to screen pixels and game positions; probability underlies randomness and simulations; binary and storage sizes use powers/indices (2^10); data representation and averages feed dashboards and data-visualisation projects; algebraic logic mirrors conditional and formula-based programming.','{"cross":1,"subject":1,"connections":1,"physics":1,"myp":2,"sciences":2,"rates":1,"unit":1,"conversions":1,"and":18,"the":2,"triangle":1,"underpin":1,"speed":1,"velocity":1,"acceleration":1,"pythagoras":1,"resolves":1,"vector":1,"components":1,"standard":1,"form":1,"indices":2,"expresses":1,"very":1,"large":1,"small":1,"quantities":1,"graphs":2,"gradients":1,"link":1,"motion":1,"chemistry":1,"ratio":1,"proportion":1,"drive":1,"mole":1,"ratios":2,"concentration":1,"percentage":3,"calculations":1,"give":1,"yield":1,"composition":1,"purity":1,"significant":1,"figures":1,"rounding":1,"relate":1,"measurement":1,"accuracy":1,"geography":1,"individuals":1,"societies":1,"time":1,"zones":1,"coordinates":1,"support":1,"map":2,"reading":1,"global":1,"scheduling":1,"change":2,"models":1,"population":1,"growth":1,"gdp":1,"resource":1,"central":1,"tendency":1,"dispersion":1,"summarise":1,"climate":1,"demographic":1,"data":3,"scale":1,"convert":1,"real":1,"distance":1,"digital":1,"design":1,"computing":1,"coordinate":1,"plane":1,"maps":1,"screen":1,"pixels":1,"game":1,"positions":1,"probability":1,"underlies":1,"randomness":1,"simulations":1,"binary":1,"storage":1,"sizes":1,"use":1,"powers":1,"representation":1,"averages":1,"feed":1,"dashboards":1,"visualisation":1,"projects":1,"algebraic":1,"logic":1,"mirrors":1,"conditional":1,"formula":1,"based":1,"programming":1}'::jsonb),
